import type { Tool } from "../../core/tools.js";

export const tool: Tool = {
  def: {
    name: "cycle_focus",
    description: "현재 사이클의 읽은 내용과 관찰을 짧게 정리해 다음 행동 후보를 만든다.",
    input_schema: {
      type: "object",
      properties: {
        code: { type: "string", description: "읽은 코드의 핵심" },
        context: { type: "string", description: "현재 맥락" },
        risk: { type: "string", description: "주요 리스크" },
        next: { type: "string", description: "다음 행동" },
      },
      required: ["code", "context"],
      additionalProperties: false,
    },
  },
  handler: async (input) => {
    const code = String(input.code ?? "").trim();
    const context = String(input.context ?? "").trim();
    const risk = String(input.risk ?? "").trim();
    const next = String(input.next ?? "").trim();
    return [`코드: ${code}`, `맥락: ${context}`, risk ? `리스크: ${risk}` : null, next ? `다음: ${next}` : null].filter(Boolean).join(" | ");
  },
  states: ["WAKE", "REFLECT"],
};

import type { Tool } from "../../core/tools.js";

export const tool: Tool = {
  def: {
    name: "wake_summary",
    description: "읽은 코드와 현재 맥락을 핵심 상태·리스크·다음 행동으로 짧게 압축한다.",
    input_schema: {
      type: "object",
      properties: {
        focus: { type: "string", description: "요약할 초점" },
        state: { type: "string", description: "현재 상태" },
        risk: { type: "string", description: "현재 리스크" },
        decision: { type: "string", description: "지금 미루고 있는 결정" },
        next: { type: "string", description: "추천 다음 행동" },
      },
      required: ["focus"],
      additionalProperties: false,
    },
  },
  handler: async (input) => {
    const focus = String(input.focus ?? "").trim();
    const state = String(input.state ?? "").trim();
    const risk = String(input.risk ?? "").trim();
    const decision = String(input.decision ?? "").trim();
    const next = String(input.next ?? "").trim();

    const parts: string[] = [];
    if (focus) parts.push(`초점: ${focus}`);
    if (state) parts.push(`상태: ${state}`);
    if (risk) parts.push(`리스크: ${risk}`);
    if (decision) parts.push(`미룬 결정: ${decision}`);
    if (next) parts.push(`다음: ${next}`);

    return parts.length ? parts.join(" | ") : "초점이 비어 있다.";
  },
  states: ["WAKE", "REFLECT"],
};

